#include<bits/stdc++.h>
using namespace std;
int a[2001];
int f[2001][2001];
vector<int> mp[2001];
int main()
{
    int n,m,c;
    scanf("%d%d%d",&n,&m,&c);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[y].push_back(x);
    }
    memset(f,-1,sizeof(f));
    f[0][1]=0;
    for(int i=1;i<=1000;i++)
    {
        for(int u=1;u<=n;u++)
        {
            for(int j:mp[u])
            {
                if(f[i-1][j]<0)
                {
                    continue;
                }
                f[i][u]=max(f[i][u],f[i-1][j]+a[u]);
            }
        }
    }
    int ans=0;
    for(int i=1;i<=1000;i++)
    {
        ans=max(ans,f[i][1]-c*i*i);
    }
    printf("%d",ans);
    return 0;
}
